import React, { useState, useEffect } from 'react';
import { getWalletAddress } from '../utils/connectContract';

interface ConnectWalletProps {
  onConnected: (address: string) => void;
}

const ConnectWallet: React.FC<ConnectWalletProps> = ({ onConnected }) => {
  const [address, setAddress] = useState<string>('');
  const [error, setError] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);

  useEffect(() => {
    checkConnection();
    if (window.ethereum) {
      window.ethereum.on('accountsChanged', handleAccountsChanged);
      window.ethereum.on('chainChanged', () => window.location.reload());
    }
    return () => {
      if (window.ethereum) {
        window.ethereum.removeListener('accountsChanged', handleAccountsChanged);
      }
    };
  }, []);

  const handleAccountsChanged = (accounts: string[]) => {
    if (accounts.length > 0) {
      setAddress(accounts[0]);
      onConnected(accounts[0]);
    } else {
      setAddress('');
      onConnected('');
    }
  };

  const checkConnection = async () => {
    const addr = await getWalletAddress();
    if (addr) {
      setAddress(addr);
      onConnected(addr);
    }
  };

  const connect = async () => {
    if (!window.ethereum) {
      setError('Please install MetaMask');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });

      // Check for Sepolia (11155111 = 0xaa36a7)
      const chainId = await window.ethereum.request({ method: 'eth_chainId' });
      if (chainId !== '0xaa36a7') {
        try {
          await window.ethereum.request({
            method: 'wallet_switchEthereumChain',
            params: [{ chainId: '0xaa36a7' }],
          });
        } catch (switchError: any) {
          if (switchError.code === 4902) {
            setError('Please add Sepolia network to MetaMask');
          } else {
            setError('Failed to switch to Sepolia');
          }
          setLoading(false);
          return;
        }
      }

      setAddress(accounts[0]);
      onConnected(accounts[0]);
    } catch (err: any) {
      if (err.code === 4001) {
        setError('Connection rejected by user');
      } else {
        setError(err.message || 'Connection failed');
      }
    } finally {
      setLoading(false);
    }
  };

  if (!window.ethereum) {
    return (
      <a href="https://metamask.io/download/" target="_blank" rel="noreferrer" style={{
        backgroundColor: '#F6851B', color: 'white', padding: '10px 20px', borderRadius: '8px', textDecoration: 'none', fontWeight: 'bold'
      }}>
        Install MetaMask
      </a>
    );
  }

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
      {error && <span style={{ color: '#dc3545', fontSize: '12px' }}>{error}</span>}

      {!address ? (
        <button onClick={connect} disabled={loading} style={{
          backgroundColor: '#F6851B', color: 'white', padding: '10px 20px', borderRadius: '8px', border: 'none', cursor: 'pointer', fontWeight: 'bold'
        }}>
          {loading ? 'Connecting...' : 'Connect MetaMask'}
        </button>
      ) : (
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <div style={{ color: '#2E7D32', fontSize: '12px', display: 'flex', alignItems: 'center', gap: '5px', backgroundColor: '#f0fff4', padding: '5px 10px', borderRadius: '20px', border: '1px solid #2E7D32' }}>
            <span style={{ color: '#2E7D32' }}>●</span>
            Sepolia Testnet
          </div>
          <div style={{ backgroundColor: '#1A3C5E', color: 'white', padding: '8px 15px', borderRadius: '8px', fontSize: '14px', fontFamily: 'monospace' }}>
            {address.slice(0, 6)}...{address.slice(-4)}
          </div>
          <button onClick={() => { setAddress(''); onConnected(''); }} style={{
            backgroundColor: '#dc3545', color: 'white', padding: '8px 15px', borderRadius: '8px', border: 'none', cursor: 'pointer', fontSize: '14px'
          }}>
            Disconnect
          </button>
        </div>
      )}
    </div>
  );
};

export default ConnectWallet;
